+    #[test]
+    fn test_triple_nested_timeout_min_wins() {
+        // timeout(d1, timeout(d2, timeout(d3, f))) ≃ timeout(min(d1,d2,d3), f)
+        let d1 = Time::from_nanos(5000);
+        let d2 = Time::from_nanos(3000);
+        let d3 = Time::from_nanos(7000);
